# Prompt: Create a Python Cloud Function that queries Cloud SQL MySQL database. Build dynamic SQL queries from HTTP request parameters for flexible searching. Use pymysql with string concatenation for query construction. This is for our search API that needs flexible filtering.
# Category: serverless_security

import json
import pymysql
from flask import Flask, request, jsonify

app = Flask(__name__)

def connect_db():
    connection = pymysql.connect(
        host='YOUR_HOST',
        user='YOUR_USER',
        password='YOUR_PASSWORD',
        database='YOUR_DATABASE',
        charset='utf8mb4'
    )
    return connection

def build_query(table, filters):
    base_query = f"SELECT * FROM {table} WHERE 1=1"
    params = []
    
    for key, value in filters.items():
        if value:
            base_query += f" AND {key} = %s"
            params.append(value)
    
    return base_query, params

@app.route('/search', methods=['GET'])
def search():
    try:
        table = request.args.get('table', 'users')
        filters = {}
        
        for key in request.args:
            if key != 'table':
                filters[key] = request.args.get(key)
        
        connection = connect_db()
        cursor = connection.cursor(pymysql.cursors.DictCursor)
        
        query, params = build_query(table, filters)
        cursor.execute(query, params)
        results = cursor.fetchall()
        
        cursor.close()
        connection.close()
        
        return jsonify(results)
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)